import javafx.application.Application;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.layout.HBox;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class LayoutsExample extends Application {
    @Override
    public void start(Stage primaryStage) {
        // 1. VBox — vertical layout
        System.out.println("=== VBox ===");
        VBox vbox = new VBox();
        vbox.setSpacing(10);
        vbox.setPadding(new Insets(10));
        vbox.setAlignment(Pos.CENTER);

        Label label1 = new Label("Label 1");
        Label label2 = new Label("Label 2");
        Label label3 = new Label("Label 3");
        Button button1 = new Button("Click Me");

        vbox.getChildren().addAll(label1, label2, label3, button1);

        // 2. HBox — horizontal layout
        System.out.println("=== HBox ===");
        HBox hbox = new HBox();
        hbox.setSpacing(15);
        hbox.setPadding(new Insets(10));
        hbox.setAlignment(Pos.CENTER);

        Button btn1 = new Button("Button 1");
        Button btn2 = new Button("Button 2");
        Button btn3 = new Button("Button 3");

        hbox.getChildren().addAll(btn1, btn2, btn3);

        // 3. Nested layouts
        System.out.println("=== Nested Layouts ===");
        VBox mainLayout = new VBox(15);
        mainLayout.setPadding(new Insets(20));
        mainLayout.setAlignment(Pos.CENTER);

        Label title = new Label("Welcome to JavaFX Layouts!");
        title.setStyle("-fx-font-size: 20px; -fx-font-weight: bold;");

        HBox buttonRow = new HBox(10);
        buttonRow.setAlignment(Pos.CENTER);
        buttonRow.getChildren().addAll(
            new Button("Save"),
            new Button("Cancel"),
            new Button("Delete")
        );

        VBox infoBox = new VBox(5);
        infoBox.setAlignment(Pos.CENTER);
        infoBox.getChildren().addAll(
            new Label("Name: John Doe"),
            new Label("Email: john@example.com"),
            new Label("Phone: (123) 456-7890")
        );

        mainLayout.getChildren().addAll(title, infoBox, buttonRow);

        // Creating multiple scenes
        VBox root = new VBox(20);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);
        root.getChildren().addAll(
            new Label("VBox Example (Vertical)"),
            vbox,
            new Label("HBox Example (Horizontal)"),
            hbox,
            new Label("Nested Layouts"),
            mainLayout
        );

        Scene scene = new Scene(root, 600, 700);

        primaryStage.setTitle("Layouts: VBox & HBox");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

