import javafx.application.Application;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.layout.HBox;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class LayoutPractice extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox vbox = new VBox(15);
        vbox.setPadding(new Insets(20));
        vbox.setAlignment(Pos.CENTER);

        Label l1 = new Label("Item 1");
        Label l2 = new Label("Item 2");
        Label l3 = new Label("Item 3");

        HBox hbox = new HBox(10);
        hbox.setAlignment(Pos.CENTER);
        Button btn1 = new Button("Add");
        Button btn2 = new Button("Edit");
        Button btn3 = new Button("Delete");
        hbox.getChildren().addAll(btn1, btn2, btn3);

        vbox.getChildren().addAll(l1, l2, l3, hbox);

        Scene scene = new Scene(vbox, 400, 300);
        primaryStage.setTitle("Layout Practice");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}
